logic [7:0] a;
logic [2:0] b;
logic [3:0] c;
assign c = a[$signed(b) +: 4];

reg [3:0] tmp;
reg [3:0] bneg;
always @(a or b) begin
  bneg = -$signed(b);
  if ($signed(b) < 0)
    tmp = a << bneg;
  else
    tmp = a >> ($signed(b));
end

reg [3:0] tmp;
reg [3:0] bneg;
always @(*) begin
  bneg = -$signed(b);
  tmp = (a << bneg) | ((4'bx) & ((1 << (-$signed(b))) - 1));
end
